import sys
import csv
import os
import json

# human-like comments in lower-case only
# args: <json_results> <history_csv>
if len(sys.argv) < 3:
    sys.exit(1)

json_path, csv_path = sys.argv[1], sys.argv[2]

# load the results generated by the individual log parsers
with open(json_path, "r") as f:
    results = json.load(f)

file_exists = os.path.isfile(csv_path)
if os.path.dirname(csv_path):
    os.makedirs(os.path.dirname(csv_path), exist_ok=True)

with open(csv_path, mode="a", newline="") as csvfile:
    # new schema includes scene, variant, and iterations
    fieldnames = ["date", "version", "scene", "variant", "rmse", "iterations", "commit"]
    writer = csv.DictWriter(csvfile, fieldnames=fieldnames)

    if not file_exists:
        writer.writeheader()

    for entry in results:
        # we pull clean keys directly from the json now
        writer.writerow(
            {
                "date": entry["timestamp"],
                "version": entry["version"],
                "scene": entry.get("scene", "unknown"),
                "variant": entry.get("variant", "default"),
                "rmse": entry["rmse_value"],
                "iterations": entry.get("iterations", 0),
                "commit": entry["commit"],
            }
        )

print(f"appended {len(results)} entries to {csv_path}")
